# Verify and apply
print("=== Description Length Check (target: 120~160) ===")
all_ok = True
for fp, nd in sorted(new_descriptions.items()):
    dl = len(nd)
    ok = 120 <= dl <= 160
    if not ok:
        all_ok = False
    print(f"{fp:35s} {dl:4d}자 {'✅' if ok else '❌'}")
print(f"Total: {len(new_descriptions)}, All OK: {all_ok}")

# Apply replacements
print("\n=== Applying replacements ===")
applied = 0
for fn, nd in sorted(new_descriptions.items()):
    fp = os.path.join(posts_dir, fn)
    with open(fp, 'r', encoding='utf-8') as f:
        c = f.read()
    m = re.search(r'^description:\s*"(.*?)"', c, re.MULTILINE)
    if m:
        nc = c.replace(m.group(0), f'description: "{nd}"', 1)
        if nc != c:
            with open(fp, 'w', encoding='utf-8') as f:
                f.write(nc)
            applied += 1
            print(f"  OK {fn}")
print(f"\nUpdated: {applied}/{len(new_descriptions)}")
